import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_cost(travel_time, waiting_time, overtime, congestion_penalty, dynamic_window_penalty):
        return travel_time + waiting_time * 1.2 + overtime * 60 + congestion_penalty * 0.1 + dynamic_window_penalty * 0.5

    def calculate_congestion_penalty(customer_pos, other_trucks):
        penalty = 0
        for truck in other_trucks:
            if np.array_equal(truck, cur_truck_pos):
                continue
            distance_to_truck = np.linalg.norm(customer_pos - truck)
            penalty += max(0, 80 - distance_to_truck)  # smaller distance increases penalty
        return penalty

    def calculate_dynamic_window_penalty(arrival_time, window_start, window_end):
        # This function penalizes less if arrival is within the time window and more as it gets closer to window end
        if arrival_time <= window_end:
            if arrival_time < window_start:
                return window_start - arrival_time
            else:
                return 0
        else:
            return (arrival_time - window_end) * 2  # Higher penalty if past time window

    min_cost = np.inf
    best_node = None
    other_trucks = [pos for pos in all_truck_pos if not np.array_equal(pos, cur_truck_pos)]

    for index, customer in enumerate(unvisited_customers):
        distance = np.linalg.norm(customer - cur_truck_pos)
        travel_time = distance / truck_speed
        arrival_time = current_time + travel_time
        window_start, window_end = time_windows[index]
        waiting_time = max(0, window_start - arrival_time)
        overtime = max(0, arrival_time - window_end)
        congestion_penalty = calculate_congestion_penalty(customer, other_trucks)
        dynamic_window_penalty = calculate_dynamic_window_penalty(arrival_time, window_start, window_end)

        cost = calculate_cost(travel_time, waiting_time, overtime, congestion_penalty, dynamic_window_penalty)

        if cost < min_cost:
            min_cost = cost
            best_node = index

    return best_node
